<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Expense Tracker</title>
<style>
    body { font-family: sans-serif; max-width: 600px; margin: 2rem auto; padding: 0 1rem; }
    h1, h2 { text-align: center; }
    .form-group { display: flex; gap: 0.5rem; flex-wrap: wrap; margin-bottom: 1rem; align-items: flex-end; }
    input, select, button { padding: 0.5rem; font-size: 1rem; }
    #amount { width: 80px; }
    #date { width: 120px; }
    #note { flex-grow: 1; }
    button { cursor: pointer; background-color: #4CAF50; color: white; border: none; }
    button:hover { background-color: #45a049; }
    #form-error { color: red; margin-bottom: 1rem; min-height: 1.2em; text-align: center;}
    .filters { background: #f4f4f4; padding: 1rem; border-radius: 4px; margin-bottom: 1rem; display: flex; gap: 1rem; align-items: center; flex-wrap: wrap; }
    .summary { margin-bottom: 1rem; }
    .cat-total { font-size: 0.9em; color: #555; margin-top: 0.25rem; }
    .expense-list { list-style: none; padding: 0; }
    .expense { display: flex; justify-content: space-between; align-items: center; padding: 0.5rem; border-bottom: 1px solid #eee; }
    .expense:last-child { border-bottom: none; }
    .exp-del { background-color: #f44336; color: white; border: none; padding: 0.25rem 0.5rem; font-size: 0.8rem; cursor: pointer; margin-left: 1rem;}
    .exp-del:hover { background-color: #d32f2f; }
</style>
</head>
<body>

<div class="container">
    <h1>Expense Tracker</h1>

    <!-- Entry Form -->
    <form id="expense-form" class="form-group">
        <input type="number" id="amount" placeholder="Amount" step="0.01">
        <select id="category">
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
        </select>
        <input type="date" id="date">
        <input type="text" id="note" placeholder="Note (optional)">
        <button type="submit" id="add-expense">Add Expense</button>
    </form>

    <div id="form-error"></div>

    <!-- Filters -->
    <div class="filters">
        <label>Category:
            <select id="filter-category">
                <option value="all">All</option>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </label>
        <label>From: <input type="date" id="filter-from"></label>
        <label>To: <input type="date" id="filter-to"></label>
    </div>

    <!-- Summary -->
    <div class="summary">
        <h2>Total: <span id="total">0.00</span></h2>
        <div id="category-breakdown"></div>
    </div>

    <!-- List -->
    <ul id="expense-list" class="expense-list"></ul>
</div>

<script>
// State
let expenses = [];

// DOM Elements
const form = document.getElementById('expense-form');
const amountInput = document.getElementById('amount');
const categorySelect = document.getElementById('category');
const dateInput = document.getElementById('date');
const noteInput = document.getElementById('note');
const addBtn = document.getElementById('add-expense');
const errorDiv = document.getElementById('form-error');
const filterCategory = document.getElementById('filter-category');
const filterFrom = document.getElementById('filter-from');
const filterTo = document.getElementById('filter-to');
const totalEl = document.getElementById('total');
const listEl = document.getElementById('expense-list');
const breakdownContainer = document.getElementById('category-breakdown');

// Categories for summary generation
const categories = ['groceries', 'transport', 'bills', 'fun'];

// Load from LocalStorage
function loadExpenses() {
    const saved = localStorage.getItem('expenses');
    if (saved) {
        expenses = JSON.parse(saved);
    }
}

// Save to LocalStorage
function saveExpenses() {
    localStorage.setItem('expenses', JSON.stringify(expenses));
}

// Validation
function validateForm() {
    const amountVal = parseFloat(amountInput.value);
    const dateVal = dateInput.value;

    if (!dateVal) return 'Date is required.';
    if (isNaN(amountVal) || amountVal <= 0) return 'Amount must be a positive number.';

    errorDiv.textContent = '';
    return null;
}

// Add Expense
form.addEventListener('submit', (e) => {
    e.preventDefault();
    const validationError = validateForm();
    if (validationError) {
        errorDiv.textContent = validationError;
        return;
    }

    const newExpense = {
        id: Date.now(), // Simple unique ID
        amount: parseFloat(amountInput.value),
        category: categorySelect.value,
        date: dateInput.value,
        note: noteInput.value || ''
    };

    expenses.push(newExpense);
    saveExpenses();

    // Reset Amount field as per spec.
    amountInput.value = ''; 
    errorDiv.textContent = '';

    render();
});

// Delete Expense
listEl.addEventListener('click', (e) => {
    if (e.target.classList.contains('exp-del')) {
        const id = parseInt(e.target.dataset.id);
        expenses = expenses.filter(exp => exp.id !== id);
        saveExpenses();
        render();
    }
});

// Filter Change Listeners
[filterCategory, filterFrom, filterTo].forEach(el => {
    el.addEventListener('change', render);
});

// Render Logic
function render() {
    // 1. Get Filters
    const catFilter = filterCategory.value;
    const fromFilter = filterFrom.value;
    const toFilter = filterTo.value;

    // 2. Filter Data
    let filteredExpenses = expenses.filter(exp => {
        if (catFilter !== 'all' && exp.category !== catFilter) return false;
        if (fromFilter && exp.date < fromFilter) return false;
        if (toFilter && exp.date > toFilter) return false;
        return true;
    });

    // 3. Sort Newest First
    filteredExpenses.sort((a, b) => new Date(b.date) - new Date(a.date));

    // 4. Render List
    listEl.innerHTML = filteredExpenses.map(exp => `
        <li class="expense">
            <div>
                <strong>${exp.amount.toFixed(2)}</strong> 
                <span style="color:#666; margin-left:0.5rem;">(${exp.category})</span>
                <br><small>${exp.date} ${exp.note ? '- ' + exp.note : ''}</small>
            </div>
            <button class="exp-del" data-id="${exp.id}">Delete</button>
        </li>
    `).join('');

    // 5. Update Total
    const total = filteredExpenses.reduce((sum, exp) => sum + exp.amount, 0);
    totalEl.textContent = total.toFixed(2);

    // 6. Update Category Breakdown
    updateCategoryBreakdown(filteredExpenses);
}

function updateCategoryBreakdown(data) {
    breakdownContainer.innerHTML = '';

    categories.forEach(cat => {
        const catTotal = data.filter(exp => exp.category === cat).reduce((sum, exp) => sum + exp.amount, 0);

        // Create element if not exists or update it. 
        let el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
        if (!el) {
            el = document.createElement('div');
            el.className = 'cat-total';
            el.setAttribute('data-cat', cat);
            breakdownContainer.appendChild(el);
        }

        const categoryLabel = cat.charAt(0).toUpperCase() + cat.slice(1);
        el.textContent = `${categoryLabel}: ${catTotal.toFixed(2)}`;
    });
}

// Init
loadExpenses();
render();
</script>

</body>
</html>
